create table dirkspzm32.pzm_vertragsarten (
    va_id                            number(20, 0) not null enable,
    va_name                          varchar2(50 char) not null enable,
    va_bemerkung                     varchar2(255 char),
    va_reset_monats_ende             number(1, 0) default 0 not null enable,
    va_loa_stunden_abrechnung        varchar2(1 char) default 'T' not null enable,
    va_bis_monat_ende_sim            varchar2(1 char) default 'F' not null enable,
    va_bis_std_auszahlen             number(3, 2),
    va_bis_std_auszahlen_zeiteinheit varchar2(2 char)
);

alter table dirkspzm32.pzm_vertragsarten
    add constraint pk_va_id primary key ( va_id )
        using index enable;


